    ; =====================================================================
    ; Soft reset the ACIA.
    ;
    ; Writing any value to the status register triggers a programmed reset.
    ;
    ; Out:
    ;   A = clobbered

    .proc {{ symbol("soft_reset") }}
        sta {{ P }}_STATUS
        DELAY_MS 100
        rts
    .endproc

