    ; =====================================================================
    ; Write a byte to a terminal.
    ;
    ; Handles CR → CR+LF conversion for terminal-style output.
    ;
    ; In (zero page):
    ;   byte = data byte to transmit
    ; Out:
    ;   A = clobbered

    .proc {{ symbol("write_terminal") }}
        lda {{ symbol("byte") }}
        cmp #$0d
        bne @raw

        ; Send CR first, then queue LF.
        jsr {{ symbol("write") }}
        lda #$0a
        sta {{ symbol("byte") }}
    @raw:
        jmp {{ symbol("write") }}
    .endproc
